import os

def serialize(config, path):
    with open(path, 'w') as file:
        # Check if config has comments attribute (ConfigParserWithComments)
        if hasattr(config, 'comments') and isinstance(config.comments, dict):
            # Write sections and options with comments
            for section in config.sections():
                if section in config.comments:
                    file.write(f"# {config.comments[section]}\n")
                file.write(f"[{section}]\n")
                for key, value in config.items(section):
                    option_key = f"{section}.{key}"
                    if option_key in config.comments:
                        file.write(f"# {config.comments[option_key]}\n")
                    file.write(f"{key} = {value}\n")
        else:
            # For generic objects, just call their write method
            config.write(file)
